    end
  end
  defp validate_url(_), do: {:error, :invalid_url}

  defp sanitize_url(url) do
    uri = URI.parse(url)
    sanitized = %URI{
      scheme: uri.scheme,
      host: String.downcase(uri.host || ""),
      port: uri.port,
      path: uri.path,
      query: uri.query
    }
    {:ok, URI.to_string(sanitized)}
  end

  defp validate_hostname(url) do
